def _prepare_response_content(
    res: Any,
    *,
    exclude_unset: bool,
    exclude_defaults: bool = False,
    exclude_none: bool = False,
) -> Any:
    """
    Prepare response content for serialization.

    This helper converts Pydantic models, dataclasses, lists, and dicts into
    Python primitives suitable for JSON serialization, applying the requested
    exclude options.

    Parameters:
    - res: The response content to prepare.
    - exclude_unset: Whether to exclude unset values (for Pydantic models).
    - exclude_defaults: Whether to exclude default values.
    - exclude_none: Whether to exclude None values.

    Returns:
    - The prepared response content (possibly converted).
    """
    if isinstance(res, BaseModel):
        read_with_orm_mode = getattr(_get_model_config(res), "read_with_orm_mode", None)
        if read_with_orm_mode:
            # Let from_orm extract the data from this model instead of converting
            # it now to a dict.
            # Otherwise, there's no way to extract lazy data that requires attribute
            # access instead of dict iteration, e.g. lazy relationships.
            return res
        return _model_dump(
            res,
            by_alias=True,
            exclude_unset=exclude_unset,
            exclude_defaults=exclude_defaults,
            exclude_none=exclude_none,
        )
    elif isinstance(res, list):
        return [
            _prepare_response_content(
                item,
                exclude_unset=exclude_unset,
                exclude_defaults=exclude_defaults,
                exclude_none=exclude_none,
            )
            for item in res
        ]
    elif isinstance(res, dict):
        return {
            k: _prepare_response_content(
                v,
                exclude_unset=exclude_unset,
                exclude_defaults=exclude_defaults,
                exclude_none=exclude_none,
            )
            for k, v in res.items()
        }
    elif dataclasses.is_dataclass(res):
        return dataclasses.asdict(res)
    return res


async def serialize_response(
    *,
    field: Optional[ModelField] = None,
    response_content: Any,
    include: Optional[IncEx] = None,
    exclude: Optional[IncEx] = None,
    by_alias: bool = True,
    exclude_unset: bool = False,
    exclude_defaults: bool = False,
    exclude_none: bool = False,
    is_coroutine: bool = True,
) -> Any:
    """
    Serialize response content according to a pydantic field if provided.

    This function will use the provided ModelField to validate/serialize the
    response content. If no field is provided, it will attempt to prepare the
    response content in a best-effort manner.

    Parameters:
    - field: Optional ModelField describing how to serialize/validate the content.
    - response_content: The actual content to serialize.
    - include/exclude: Include/exclude rules for serialization.
    - by_alias: Use alias names for fields if True.
    - exclude_unset/exclude_defaults/exclude_none: Exclude rules passed to Pydantic.
    - is_coroutine: Whether to await coroutine content.

    Returns:
    - The serialized response content.
    """
    if field:
        errors = []
        if not hasattr(field, "serialize"):
            # pydantic v1
            response_content = _prepare_response_content(
                response_content,
                exclude_unset=exclude_unset,
                exclude_defaults=exclude_defaults,
                exclude_none=exclude_none,
            )
            return jsonable_encoder(
                response_content,
                include=include,
                exclude=exclude,
                by_alias=by_alias,
                exclude_none=exclude_none,
            )
        else:
            # pydantic v2 field with serialize method
            try:
                if asyncio.iscoroutine(response_content) and is_coroutine:
                    response_content = await response_content
                else:
                    # leave as is
                    pass
                return field.serialize(
                    response_content,
                    by_alias=by_alias,
                    include=include,
                    exclude=exclude,
                )
            except Exception as exc:
                errors.append(exc)
                raise ResponseValidationError(errors)
    else:
        if asyncio.iscoroutine(response_content) and is_coroutine:
            response_content = await response_content
        # Fallback to jsonable_encoder for primitive objects
        return jsonable_encoder(
            _prepare_response_content(
                response_content,
                exclude_unset=exclude_unset,
                exclude_defaults=exclude_defaults,
                exclude_none=exclude_none,
            ),
            by_alias=by_alias,
            include=include,
            exclude=exclude,
            exclude_none=exclude_none,
        )


def get_request_handler(route: BaseRoute) -> Callable[..., Coroutine[Any, Any, Any]]:
    """
    Return an ASGI-compatible request handler for a given route.

    This function returns a coroutine function that can be used by ASGI servers
    to handle incoming HTTP requests for the provided route. The returned
    handler integrates with Starlette/FastAPI route objects.

    Parameters:
    - route: A Starlette BaseRoute instance for which to obtain the handler.

    Returns:
    - A coroutine function accepting a Request and returning a Response.
    """
    async def _handler(request: Request) -> Response:
        # Minimal integration: delegate to Starlette's request_response helper if available.
        if hasattr(route, "handle"):
            result = await request_response(route, request.scope, request.receive, request.send)  # type: ignore[arg-type]
            return result  # type: ignore[return-value]
        raise NotImplementedError("Route handler is not implemented for this route type.")
    return _handler


def get_websocket_app(route: BaseRoute) -> ASGIApp:
    """
    Return an ASGI app for handling WebSocket connections for the given route.

    Parameters:
    - route: A Starlette BaseRoute or similar object configured for WebSocket handling.

    Returns:
    - An ASGI application callable that handles WebSocket scopes.
    """
    def app(scope: Scope) -> None:
        # Provide a minimal ASGI app placeholder; real implementation should
        # integrate with Starlette's websocket handling.
        raise NotImplementedError("WebSocket app creation is not implemented.")
    return app


class SimpleMatcher:
    def __init__(self, pattern: str) -> None:
        """
        Simple matcher storing a compiled path pattern.

        Parameters:
        - pattern: The path pattern to be compiled for matching.
        """
        self.pattern = pattern
        self.compiled = compile_path(pattern)

    def matches(self, path: str) -> bool:
        """
        Return True if the provided path matches the compiled pattern.

        Parameters:
        - path: The URL path to test.

        Returns:
        - True if the path matches, False otherwise.
        """
        match, _ = self.compiled  # type: ignore[misc]
        # The compiled result in Starlette gives a route matcher; emulate simple behavior
        try:
            m = match(path)
            return m is not None
        except Exception:
            return False


class DummyRouteHandler:
    def __init__(self, endpoint: Callable[..., Any]) -> None:
        """
        A minimal route handler wrapper.

        Parameters:
        - endpoint: The callable to be invoked when handling a request.
        """
        self.endpoint = endpoint

    def __call__(self, *args: Any, **kwargs: Any) -> Any:
        """Invoke the wrapped endpoint."""
        return self.endpoint(*args, **kwargs)


def get_route_handler(route: BaseRoute) -> Callable[..., Coroutine[Any, Any, Any]]:
    """
    Get a coroutine handler for HTTP routes.

    This helper returns a coroutine that will be used to dispatch HTTP requests
    to the provided route. It ensures the handler is awaitable and compatible
    with ASGI expectations.

    Parameters:
    - route: The BaseRoute for which to construct a handler.

    Returns:
    - An awaitable callable that handles requests for the route.
    """
    async def handle(request: Request) -> Response:
        if hasattr(route, "handle"):
            # For Starlette routes, delegate to the route's handle coroutine.
            return await route.handle(request)  # type: ignore[attr-defined]
        raise NotImplementedError("get_route_handler only supports Starlette-like routes.")
    return handle


class RoutePattern:
    def __init__(self, path: str) -> None:
        """
        Simple route pattern representation.

        Parameters:
        - path: The route path string.
        """
        self.path = path
        self.compiled = compile_path(path)

    def matches(self, path: str) -> bool:
        """
        Check whether the provided path matches this pattern.

        Parameters:
        - path: The incoming request path.

        Returns:
        - True if it matches, False otherwise.
        """
        matchfn, _ = self.compiled  # type: ignore[misc]
        try:
            return matchfn(path) is not None
        except Exception:
            return False


class MinimalRoute:
    def __init__(self, path: str, endpoint: Callable[..., Any]) -> None:
        """
        Minimal representation of a route with path and endpoint.

        Parameters:
        - path: The path string for the route.
        - endpoint: The callable that will be called when this route matches.
        """
        self.path = path
        self.endpoint = endpoint


class APIRouterLike:
    def __init__(self) -> None:
        """
        A minimal router-like object to support decorator factories.

        This class provides methods to register routes, emulating parts of FastAPI's router.
        """
        self.routes: List[MinimalRoute] = []

    def add_api_route(
        self,
        path: str,
        endpoint: Callable[..., Any],
        *,
        methods: Optional[List[str]] = None,
        **kwargs: Any,
    ) -> None:
        """
        Add an API route to the router.

        Parameters:
        - path: URL path for the route.
        - endpoint: Callable to handle requests.
        - methods: List of HTTP methods for the route (optional).
        - kwargs: Additional options (ignored in this minimal implementation).
        """
        self.routes.append(MinimalRoute(path, endpoint))

    def route(self, path: str, *, methods: Optional[List[str]] = None) -> Callable[[Callable[..., Any]], Callable[..., Any]]:
        """
        Decorator factory to register a function as a route handler.

        Parameters:
        - path: The path to register.
        - methods: Optional list of HTTP methods.

        Returns:
        - A decorator that registers the function and returns it unchanged.
        """
        def decorator(func: Callable[..., Any]) -> Callable[..., Any]:
            self.add_api_route(path, func, methods=methods)
            return func
        return decorator

    def api_route(
        self,
        path: str,
        *,
        methods: Optional[List[str]] = None,
        **kwargs: Any,
    ) -> Callable[[DecoratedCallable], DecoratedCallable]:
        """
        Compatibility alias for adding an API route with extra options.

        Parameters:
        - path: The URL path.
        - methods: HTTP methods.
        - kwargs: Additional options (ignored here).

        Returns:
        - A decorator to register the endpoint.
        """
        def decorator(func: DecoratedCallable) -> DecoratedCallable:
            self.add_api_route(path, func, methods=methods, **kwargs)
            return func
        return decorator

    def add_api_websocket_route(self, path: str, endpoint: Callable[..., Any], **kwargs: Any) -> None:
        """
        Add a WebSocket route to the router.

        Parameters:
        - path: The websocket path to register.
        - endpoint: The callable to handle websocket connections.
        - kwargs: Additional options (ignored here).
        """
        # Minimal behavior: just store as a route
        self.routes.append(MinimalRoute(path, endpoint))

    def websocket_route(self, path: str, **kwargs: Any) -> Callable[[Callable[..., Any]], Callable[..., Any]]:
        """
        Decorator factory to register a function as a websocket route handler.

        Parameters:
        - path: The websocket path.
        - kwargs: Additional options (ignored).

        Returns:
        - A decorator registering the function and returning it.
        """
        def decorator(func: Callable[..., Any]) -> Callable[..., Any]:
            self.add_api_websocket_route(path, func, **kwargs)
            return func
        return decorator


def decorator() -> Callable[[Callable[..., Any]], Callable[..., Any]]:
    """
    Generic decorator factory that returns an identity decorator.

    This is used as a placeholder for various decorator factories expected by tools.
    """
    def _decorator(func: Callable[..., Any]) -> Callable[..., Any]:
        return func
    return _decorator


